import Menu from './menu';
import Sidebar from './sidebar';

import axios from 'axios';

import 'normalize.css';
import styles from '../scss/index.scss';

(function() {
    const pathName = window.location.pathname;
    
    let sidebarPath = 'homesidebar';

    const locales = ['anc', 'lax', 'nyc', 'dc'];

    for (let i = 0; i < locales.length; i++) {
        if (pathName.startsWith(`/${locales[i]}/`)) {
            sidebarPath = `${locales[i]}sidebar`;
            break;
        }
    }

    axios.get(`/${sidebarPath}/`)
        .then((resp) => {
            return resp.data;
        })
        .then((html) => {
            // load the sidebar frag
            const docFrag = document.createDocumentFragment();
            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = html;

            const sidebar = tempDiv.querySelector('#sidebar');
            const main = document.getElementById('main');
            main.appendChild(sidebar);
        })
        .then(() => {
            Menu.init();
            Sidebar.init();
        });
}());
